// app.js - With dependency verification
const express = require('express');
const UAParser = require('ua-parser-js');
const crypto = require('crypto');

const app = express();

// Verify critical module integrity at runtime
function verifyModuleIntegrity(modulePath, expectedHash) {
  const fs = require('fs');
  const content = fs.readFileSync(require.resolve(modulePath));
  const hash = crypto.createHash('sha256').update(content).digest('hex');
  if (hash !== expectedHash) {
    console.error(`SECURITY: Module ${modulePath} integrity check failed`);
    process.exit(1);
  }
  return true;
}

// Startup integrity check for critical dependencies
if (process.env.NODE_ENV === 'production') {
  verifyModuleIntegrity('ua-parser-js', process.env.UAPARSER_HASH);
}

app.get('/api/user-agent', (req, res) => {
  const parser = new UAParser(req.headers['user-agent']);
  const result = parser.getResult();
  res.json(result);
});

app.listen(3000);
