**Key Security Controls**:
- **Exact version pinning**: No `^` or `~` - exact versions only prevents auto-upgrade to compromised versions
- **package-lock.json**: Ensures reproducible builds with exact dependency tree
- **ignore-scripts**: Prevents automatic execution of postinstall scripts that could contain malware
- **npm audit**: Automated vulnerability scanning before deployment
- **Engine constraints**: Ensures consistent Node.js version across environments

A comprehensive supply chain security pipeline requires multiple layers of defense, from development through production. Here's a production-ready approach based on lessons from incidents like ua-parser-js, event-stream, and colors.js compromises.

**PRODUCTION PATTERN**:

```javascript
// scripts/verify-dependencies.js - Pre-deployment verification
const { execSync } = require('child_process');
const fs = require('fs');
const crypto = require('crypto');
const path = require('path');

class DependencyVerifier {
  constructor(options = {}) {
    this.allowedLicenses = options.allowedLicenses || [
      'MIT', 'Apache-2.0', 'BSD-2-Clause', 'BSD-3-Clause', 'ISC'
    ];
    this.criticalPackages = options.criticalPackages || [
      'express', 'jsonwebtoken', 'bcrypt', 'helmet'
    ];
    this.maxVulnerabilitySeverity = options.maxVulnerabilitySeverity || 'moderate';
  }

  async verifyAll() {
    console.log('🔒 Starting dependency security verification...\n');

    const results = {
      lockfileIntegrity: await this.verifyLockfile(),
      auditResults: await this.runSecurityAudit(),
      licenseCompliance: await this.checkLicenses(),
      signatureVerification: await this.verifySignatures(),
      deprecationCheck: await this.checkDeprecated(),
      supplyChainRisk: await this.assessSupplyChainRisk()
    };

    return this.generateReport(results);
  }

  async verifyLockfile() {
    console.log('📋 Verifying package-lock.json integrity...');

    const lockfilePath = path.join(process.cwd(), 'package-lock.json');

    if (!fs.existsSync(lockfilePath)) {
      throw new Error('CRITICAL: package-lock.json is missing!');
    }

    // Verify lockfile hasn't been tampered with
    const lockfile = JSON.parse(fs.readFileSync(lockfilePath, 'utf8'));

    // Check for integrity hashes
    const packages = lockfile.packages || {};
    let missingIntegrity = [];

    for (const [pkg, info] of Object.entries(packages)) {
      if (pkg && !info.integrity && !pkg.startsWith('node_modules/')) {
        missingIntegrity.push(pkg);
      }
    }

    if (missingIntegrity.length > 0) {
      console.warn(`⚠️  Packages missing integrity hashes: ${missingIntegrity.length}`);
    }

    // Verify npm ci would succeed (lockfile matches package.json)
    try {
      execSync('npm ci --dry-run', { stdio: 'pipe' });
      console.log('✅ Lockfile integrity verified\n');
      return { status: 'pass', missingIntegrity };
    } catch (error) {
      throw new Error('CRITICAL: package-lock.json is out of sync!');
    }
  }

  async runSecurityAudit() {
    console.log('🔍 Running security audit...');

    try {
      // Run npm audit and capture output
      const auditOutput = execSync('npm audit --json', { 
        encoding: 'utf8',
        stdio: ['pipe', 'pipe', 'pipe']
      });
      const audit = JSON.parse(auditOutput);

      const vulnerabilities = audit.metadata?.vulnerabilities || {};
      const critical = vulnerabilities.critical || 0;
      const high = vulnerabilities.high || 0;
      const moderate = vulnerabilities.moderate || 0;

      console.log(`   Critical: ${critical}, High: ${high}, Moderate: ${moderate}`);

      if (critical > 0 || high > 0) {
        throw new Error(`BLOCKING: ${critical} critical, ${high} high vulnerabilities found`);
      }

      console.log('✅ Security audit passed\n');
      return { status: 'pass', vulnerabilities };

    } catch (error) {
      if (error.message.includes('BLOCKING')) {
        throw error;
      }
      // npm audit returns non-zero on vulnerabilities
      const output = error.stdout?.toString() || '{}';
      const audit = JSON.parse(output);
      const vulns = audit.metadata?.vulnerabilities || {};

      if ((vulns.critical || 0) > 0 || (vulns.high || 0) > 0) {
        throw new Error(`BLOCKING: Found critical/high vulnerabilities`);
      }

      console.log('✅ Security audit passed (with warnings)\n');
      return { status: 'warning', vulnerabilities: vulns };
    }
  }

  async checkLicenses() {
    console.log('📜 Checking license compliance...');

    try {
      const output = execSync('npx license-checker --json', { 
        encoding: 'utf8',
        stdio: ['pipe', 'pipe', 'pipe']
      });
      const licenses = JSON.parse(output);

      const violations = [];

      for (const [pkg, info] of Object.entries(licenses)) {
        const license = info.licenses;
        if (license && !this.allowedLicenses.some(l => 
          license.includes(l) || license === 'UNLICENSED'
        )) {
          violations.push({ package: pkg, license });
        }
      }

      if (violations.length > 0) {
        console.warn(`⚠️  License violations: ${violations.length}`);
        violations.forEach(v => console.warn(`   - ${v.package}: ${v.license}`));
      }

      console.log('✅ License check completed\n');
      return { status: violations.length > 0 ? 'warning' : 'pass', violations };

    } catch (error) {
      console.warn('⚠️  Could not complete license check\n');
      return { status: 'skipped', error: error.message };
    }
  }

  async verifySignatures() {
    console.log('🔐 Verifying package signatures...');

    try {
      // npm v8.6.0+ supports signature verification
      execSync('npm audit signatures', { 
        encoding: 'utf8',
        stdio: ['pipe', 'pipe', 'pipe']
      });
      console.log('✅ Package signatures verified\n');
      return { status: 'pass' };
    } catch (error) {
      const output = error.stderr?.toString() || error.message;
      if (output.includes('invalid')) {
        throw new Error('CRITICAL: Invalid package signatures detected!');
      }
      console.log('✅ Package signatures verified (with warnings)\n');
      return { status: 'warning', message: output };
    }
  }

  async checkDeprecated() {
    console.log('📦 Checking for deprecated packages...');

    const output = execSync('npm outdated --json || true', { encoding: 'utf8' });
    let outdated = {};

    try {
      outdated = JSON.parse(output || '{}');
    } catch (e) {
      outdated = {};
    }

    const deprecated = [];
    const majorOutdated = [];

    for (const [pkg, info] of Object.entries(outdated)) {
      if (info.deprecated) {
        deprecated.push(pkg);
      }
      // Check for major version differences
      const current = info.current?.split('.')[0];
      const latest = info.latest?.split('.')[0];
      if (current && latest && parseInt(latest) - parseInt(current) >= 2) {
        majorOutdated.push({ package: pkg, current: info.current, latest: info.latest });
      }
    }

    if (deprecated.length > 0) {
      console.warn(`⚠️  Deprecated packages: ${deprecated.join(', ')}`);
    }

    console.log('✅ Deprecation check completed\n');
    return { status: 'pass', deprecated, majorOutdated };
  }

  async assessSupplyChainRisk() {
    console.log('⛓️  Assessing supply chain risk...');

    const packageJson = JSON.parse(fs.readFileSync('package.json', 'utf8'));
    const deps = { 
      ...packageJson.dependencies, 
      ...packageJson.devDependencies 
    };

    const risks = [];

    for (const [pkg, version] of Object.entries(deps)) {
      // Check for risky version patterns
      if (version === '*' || version === 'latest') {
        risks.push({ package: pkg, risk: 'critical', reason: 'Unpinned version' });
      } else if (version.startsWith('>=') || version.startsWith('>')) {
        risks.push({ package: pkg, risk: 'high', reason: 'Open-ended version range' });
      } else if (version.startsWith('^') && version.includes('0.')) {
        risks.push({ package: pkg, risk: 'medium', reason: 'Caret range on 0.x version' });
      }

      // Check for GitHub/URL dependencies
      if (version.includes('github') || version.includes('git+')) {
        risks.push({ package: pkg, risk: 'high', reason: 'Git dependency (unverified)' });
      }
    }

    const criticalRisks = risks.filter(r => r.risk === 'critical');
    if (criticalRisks.length > 0) {
      throw new Error(`BLOCKING: ${criticalRisks.length} critical supply chain risks`);
    }

    console.log('✅ Supply chain risk assessment completed\n');
    return { status: risks.length > 0 ? 'warning' : 'pass', risks };
  }

  generateReport(results) {
    const report = {
      timestamp: new Date().toISOString(),
      status: 'pass',
      results
    };

    for (const [check, result] of Object.entries(results)) {
      if (result.status === 'fail') {
        report.status = 'fail';
        break;
      }
      if (result.status === 'warning' && report.status !== 'fail') {
        report.status = 'warning';
      }
    }

    console.log('═'.repeat(50));
    console.log(`📊 FINAL STATUS: ${report.status.toUpperCase()}`);
    console.log('═'.repeat(50));

    return report;
  }
}

