// runtime/dependency-monitor.js - Runtime monitoring
const fs = require('fs');
const https = require('https');
const crypto = require('crypto');

class RuntimeDependencyMonitor {
  constructor(options = {}) {
    this.alertWebhook = options.alertWebhook;
    this.checkInterval = options.checkInterval || 3600000; // 1 hour
    this.knownHashes = new Map();
    this.loadKnownHashes();
  }

  loadKnownHashes() {
    try {
      const hashFile = fs.readFileSync('.dependency-hashes.json', 'utf8');
      const hashes = JSON.parse(hashFile);
      for (const [pkg, hash] of Object.entries(hashes)) {
        this.knownHashes.set(pkg, hash);
      }
    } catch (error) {
      console.warn('No dependency hash file found, generating...');
      this.generateHashes();
    }
  }

  generateHashes() {
    const packageJson = require('../package.json');
    const deps = Object.keys(packageJson.dependencies || {});

    for (const dep of deps) {
      try {
        const mainFile = require.resolve(dep);
        const content = fs.readFileSync(mainFile);
        const hash = crypto.createHash('sha256').update(content).digest('hex');
        this.knownHashes.set(dep, hash);
      } catch (e) {
        console.warn(`Could not hash ${dep}`);
      }
    }

    // Save hashes
    const hashObj = Object.fromEntries(this.knownHashes);
    fs.writeFileSync('.dependency-hashes.json', JSON.stringify(hashObj, null, 2));
  }

  verifyIntegrity() {
    const violations = [];

    for (const [pkg, expectedHash] of this.knownHashes) {
      try {
        const mainFile = require.resolve(pkg);
        const content = fs.readFileSync(mainFile);
        const currentHash = crypto.createHash('sha256').update(content).digest('hex');

        if (currentHash !== expectedHash) {
          violations.push({
            package: pkg,
            expected: expectedHash,
            actual: currentHash,
            timestamp: new Date().toISOString()
          });
        }
      } catch (e) {
        violations.push({
          package: pkg,
          error: 'Could not verify',
          timestamp: new Date().toISOString()
        });
      }
    }

    if (violations.length > 0) {
      this.handleViolation(violations);
    }

    return violations;
  }

  handleViolation(violations) {
    console.error('🚨 SECURITY ALERT: Dependency integrity violation detected!');
    console.error(JSON.stringify(violations, null, 2));

    // Send alert
    if (this.alertWebhook) {
      this.sendAlert(violations);
    }

    // In production, you might want to:
    // - Terminate the process
    // - Switch to fallback mode
    // - Alert security team
    if (process.env.NODE_ENV === 'production') {
      process.exit(1);
    }
  }

  sendAlert(violations) {
    const payload = JSON.stringify({
      type: 'dependency_integrity_violation',
      severity: 'critical',
      violations,
      hostname: require('os').hostname(),
      timestamp: new Date().toISOString()
    });

    const url = new URL(this.alertWebhook);
    const req = https.request({
      hostname: url.hostname,
      path: url.pathname,
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Content-Length': Buffer.byteLength(payload)
      }
    });

    req.write(payload);
    req.end();
  }

  startMonitoring() {
    // Initial check
    this.verifyIntegrity();

    // Periodic checks
    setInterval(() => {
      this.verifyIntegrity();
    }, this.checkInterval);

    console.log('🔒 Runtime dependency monitoring active');
  }
}

module.exports = RuntimeDependencyMonitor;
