import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.time.Instant;
import java.util.*;
import java.util.regex.Pattern;
import com.fasterxml.jackson.databind.JsonNode;
import com.fasterxml.jackson.databind.ObjectMapper;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

public class DependencySecurityScanner {
    private static final Logger logger = LoggerFactory.getLogger(DependencySecurityScanner.class);
    private static final ObjectMapper mapper = new ObjectMapper();

    // Critical CVEs that should immediately block deployment
    private static final Set<String> CRITICAL_CVES = Set.of(
        "CVE-2021-44228",  // Log4Shell
        "CVE-2021-45046",  // Log4j additional RCE
        "CVE-2022-22965",  // Spring4Shell
        "CVE-2022-42889",  // Apache Text4Shell
        "CVE-2023-44487",  // HTTP/2 Rapid Reset
        "CVE-2024-21626"   // RunC container escape
    );

    private final double cvssThreshold;
    private final AlertService alertService;
    private final AuditLogger auditLogger;

    public DependencySecurityScanner(double cvssThreshold, 
                                      AlertService alertService,
                                      AuditLogger auditLogger) {
        this.cvssThreshold = cvssThreshold;
        this.alertService = alertService;
        this.auditLogger = auditLogger;
    }

    public ScanResult scanDependencies(Path reportPath) throws IOException {
        logger.info("Starting dependency security scan");
        Instant startTime = Instant.now();

        JsonNode report = mapper.readTree(Files.readString(reportPath));
        List<Vulnerability> criticalVulns = new ArrayList<>();
        List<Vulnerability> highVulns = new ArrayList<>();
        List<Vulnerability> mediumVulns = new ArrayList<>();

        JsonNode dependencies = report.get("dependencies");
        if (dependencies == null || !dependencies.isArray()) {
            throw new IllegalStateException("Invalid dependency-check report format");
        }

        for (JsonNode dep : dependencies) {
            JsonNode vulns = dep.get("vulnerabilities");
            if (vulns == null || !vulns.isArray()) continue;

            String depName = dep.get("fileName").asText();

            for (JsonNode vuln : vulns) {
                String cveId = vuln.get("name").asText();
                double cvssScore = vuln.has("cvssv3") 
                    ? vuln.get("cvssv3").get("baseScore").asDouble()
                    : vuln.get("cvssv2").get("score").asDouble();
                String severity = vuln.get("severity").asText();

                Vulnerability v = new Vulnerability(
                    cveId, depName, cvssScore, severity,
                    vuln.has("description") ? vuln.get("description").asText() : ""
                );

                // Categorize by severity
                if (CRITICAL_CVES.contains(cveId) || cvssScore >= 9.0) {
                    criticalVulns.add(v);
                    alertService.sendCriticalAlert(
                        "CRITICAL: " + cveId + " in " + depName,
                        "Immediate action required. CVSS: " + cvssScore
                    );
                } else if (cvssScore >= 7.0) {
                    highVulns.add(v);
                } else if (cvssScore >= 4.0) {
                    mediumVulns.add(v);
                }

                auditLogger.logVulnerabilityFound(v);
            }
        }

        ScanResult result = new ScanResult(
            criticalVulns, highVulns, mediumVulns,
            startTime, Instant.now()
        );

        // Fail build if critical vulnerabilities found
        if (!criticalVulns.isEmpty()) {
            logger.error("SECURITY GATE FAILED: {} critical vulnerabilities found", 
                        criticalVulns.size());
            result.setDeploymentBlocked(true);
        } else if (!highVulns.isEmpty() && highVulns.stream()
                .anyMatch(v -> v.getCvssScore() >= cvssThreshold)) {
            logger.warn("SECURITY GATE FAILED: High severity vulnerabilities above threshold");
            result.setDeploymentBlocked(true);
        }

        return result;
    }

    public void generateSBOM(Path outputPath) throws IOException {
        // Generate Software Bill of Materials for supply chain transparency
        ProcessBuilder pb = new ProcessBuilder(
            "cyclonedx-maven-plugin:makeAggregateBom",
            "-DoutputFormat=json",
            "-DoutputName=sbom"
        );
        pb.inheritIO();
        Process p = pb.start();
        try {
            int exitCode = p.waitFor();
            if (exitCode != 0) {
                throw new RuntimeException("SBOM generation failed");
            }
            logger.info("SBOM generated at {}", outputPath);
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
            throw new RuntimeException("SBOM generation interrupted", e);
        }
    }
}

class Vulnerability {
    private final String cveId;
    private final String dependency;
    private final double cvssScore;
    private final String severity;
    private final String description;

    public Vulnerability(String cveId, String dependency, double cvssScore,
                        String severity, String description) {
        this.cveId = cveId;
        this.dependency = dependency;
        this.cvssScore = cvssScore;
        this.severity = severity;
        this.description = description;
    }

    public String getCveId() { return cveId; }
    public String getDependency() { return dependency; }
    public double getCvssScore() { return cvssScore; }
    public String getSeverity() { return severity; }
    public String getDescription() { return description; }
}

class ScanResult {
    private final List<Vulnerability> critical;
    private final List<Vulnerability> high;
    private final List<Vulnerability> medium;
    private final Instant startTime;
    private final Instant endTime;
    private boolean deploymentBlocked;

    public ScanResult(List<Vulnerability> critical, List<Vulnerability> high,
                     List<Vulnerability> medium, Instant startTime, Instant endTime) {
        this.critical = critical;
        this.high = high;
        this.medium = medium;
