go 1.21

require (
    github.com/mycompany/internal-auth v1.2.3      // Private package
    github.com/mycompany/internal-logging v0.5.0   // Private package
    github.com/gin-gonic/gin v1.9.1
)

// No GOPRIVATE configured!
// No GOPROXY restrictions!
// No checksum database exclusions!
```

