declare(strict_types=1);

require_once __DIR__ . '/../vendor/autoload.php';

use GuzzleHttp\Client;
use Monolog\Logger;
use Monolog\Handler\StreamHandler;
use Monolog\Handler\RotatingFileHandler;

class SecureApplication {
    private Logger $logger;
    private Client $client;

    public function __construct() {
        // Verify composer.lock hash matches
        $this->verifyDependencyIntegrity();

        $this->logger = new Logger('app');
        $this->logger->pushHandler(
            new RotatingFileHandler('/var/log/app/app.log', 30, Logger::INFO)
        );

        $this->client = new Client([
            'timeout' => 30,
            'verify' => true,  // SSL verification enabled
            'http_errors' => true
        ]);
    }

    private function verifyDependencyIntegrity(): void {
        $lockFile = __DIR__ . '/../composer.lock';
        $hashFile = __DIR__ . '/../composer.lock.sha256';

        if (!file_exists($lockFile) || !file_exists($hashFile)) {
            throw new RuntimeException('Dependency integrity files missing');
        }

        $expectedHash = trim(file_get_contents($hashFile));
        $actualHash = hash_file('sha256', $lockFile);

        if (!hash_equals($expectedHash, $actualHash)) {
            $this->emergencyLog('Dependency integrity check failed');
            throw new RuntimeException('Dependency tampering detected');
        }
    }

    private function emergencyLog(string $message): void {
        error_log(sprintf('[SECURITY] %s at %s', $message, date('Y-m-d H:i:s')));
    }
}
