**Key Security Controls**:
- **Pinned versions** with caret notation (`^3.4.0`) prevents unexpected major/minor upgrades while allowing patches
- **Dev dependencies separated** - PHPUnit only in require-dev, not deployed to production
- **Lock file commitment** - composer.lock ensures reproducible builds across environments
- **Plugin restrictions** - Explicit allow-list prevents malicious plugin execution
- **Integrity verification** - SHA256 hash check on composer.lock detects tampering

Excellent question. Production-grade supply chain security requires multiple layers: pre-installation scanning, runtime integrity monitoring, and automated vulnerability detection. Here's a comprehensive approach based on lessons from real-world incidents like the ua-parser-js and event-stream compromises.

**PRODUCTION PATTERN**:

```php
<?php
// src/Security/DependencySecurityManager.php
declare(strict_types=1);

namespace App\Security;

use App\Logging\SecurityLogger;
use App\Monitoring\AlertingService;
use RuntimeException;

class DependencySecurityManager {
    private const VULNERABILITY_DB = 'https://packagist.org/api/security-advisories/';
    private const ALLOWED_PACKAGE_SOURCES = [
        'https://repo.packagist.org',
        'https://packagist.org'
    ];

    private SecurityLogger $logger;
    private AlertingService $alerting;
    private string $projectRoot;

    public function __construct(
        SecurityLogger $logger,
        AlertingService $alerting,
        string $projectRoot
    ) {
        $this->logger = $logger;
        $this->alerting = $alerting;
        $this->projectRoot = $projectRoot;
    }

    /**
     * Run full security audit before deployment
     */
    public function auditBeforeDeployment(): array {
        $results = [
            'vulnerabilities' => $this->checkVulnerabilities(),
            'integrity' => $this->verifyPackageIntegrity(),
            'sources' => $this->validatePackageSources(),
            'licenses' => $this->checkLicenseCompliance(),
            'abandoned' => $this->detectAbandonedPackages()
        ];

        $criticalIssues = array_filter($results, fn($r) => $r['severity'] === 'CRITICAL');

        if (!empty($criticalIssues)) {
            $this->alerting->sendCriticalAlert(
                'Deployment blocked: Critical dependency issues',
                $criticalIssues
            );
            throw new RuntimeException('Deployment blocked due to security issues');
        }

        $this->logger->info('Dependency audit passed', $results);
        return $results;
    }

    /**
     * Check installed packages against vulnerability database
     */
    private function checkVulnerabilities(): array {
        $lockFile = $this->projectRoot . '/composer.lock';

        if (!file_exists($lockFile)) {
            return [
                'severity' => 'CRITICAL',
                'message' => 'composer.lock not found'
            ];
        }

        $lockData = json_decode(file_get_contents($lockFile), true);
        $packages = [];

        foreach ($lockData['packages'] ?? [] as $package) {
            $packages[$package['name']] = $package['version'];
        }

        // Query Packagist Security Advisories API
        $advisories = $this->fetchSecurityAdvisories(array_keys($packages));
        $vulnerabilities = [];

        foreach ($advisories as $packageName => $packageAdvisories) {
            foreach ($packageAdvisories as $advisory) {
                $installedVersion = $packages[$packageName] ?? null;
                if ($installedVersion && $this->isVersionAffected($installedVersion, $advisory)) {
                    $vulnerabilities[] = [
                        'package' => $packageName,
                        'version' => $installedVersion,
                        'cve' => $advisory['cve'] ?? 'N/A',
                        'title' => $advisory['title'],
                        'severity' => $this->mapSeverity($advisory['severity'] ?? 'unknown')
                    ];
                }
            }
        }

        return [
            'severity' => empty($vulnerabilities) ? 'OK' : 'CRITICAL',
            'vulnerabilities' => $vulnerabilities,
            'scanned_packages' => count($packages)
        ];
    }

    /**
     * Verify package integrity using content hashes
     */
    private function verifyPackageIntegrity(): array {
        $lockFile = $this->projectRoot . '/composer.lock';
        $lockData = json_decode(file_get_contents($lockFile), true);
        $failures = [];

        foreach ($lockData['packages'] ?? [] as $package) {
            $expectedHash = $package['dist']['shasum'] ?? null;
            if (!$expectedHash) {
                continue; // Skip packages without hash
            }

            $packagePath = $this->projectRoot . '/vendor/' . $package['name'];
            if (!is_dir($packagePath)) {
                continue;
            }

            // Verify critical files haven't been modified
            $composerJson = $packagePath . '/composer.json';
            if (file_exists($composerJson)) {
                $currentHash = hash_file('sha256', $composerJson);
                $storedHash = $this->getStoredHash($package['name']);

                if ($storedHash && !hash_equals($storedHash, $currentHash)) {
                    $failures[] = [
                        'package' => $package['name'],
                        'reason' => 'composer.json modified after installation'
                    ];
                }
            }
        }

        return [
            'severity' => empty($failures) ? 'OK' : 'CRITICAL',
            'failures' => $failures
        ];
    }

    /**
     * Validate all packages come from approved sources
     */
    private function validatePackageSources(): array {
        $lockData = json_decode(
            file_get_contents($this->projectRoot . '/composer.lock'),
            true
        );

        $untrustedSources = [];

        foreach ($lockData['packages'] ?? [] as $package) {
            $source = $package['dist']['url'] ?? $package['source']['url'] ?? '';
            $isTrusted = false;

            foreach (self::ALLOWED_PACKAGE_SOURCES as $allowedSource) {
                if (str_starts_with($source, $allowedSource)) {
                    $isTrusted = true;
                    break;
                }
            }

            if (!$isTrusted && !empty($source)) {
                $untrustedSources[] = [
                    'package' => $package['name'],
                    'source' => $source
                ];
            }
        }

        return [
            'severity' => empty($untrustedSources) ? 'OK' : 'HIGH',
            'untrusted' => $untrustedSources
        ];
    }

    /**
     * Runtime monitoring - call periodically via cron
     */
    public function runtimeIntegrityCheck(): void {
        $vendorAutoload = $this->projectRoot . '/vendor/autoload.php';
        $expectedHash = $this->getStoredHash('autoload.php');

        if ($expectedHash) {
            $currentHash = hash_file('sha256', $vendorAutoload);

            if (!hash_equals($expectedHash, $currentHash)) {
                $this->alerting->sendCriticalAlert(
                    'CRITICAL: Vendor autoload.php modified at runtime',
                    [
                        'expected' => $expectedHash,
                        'actual' => $currentHash,
                        'server' => gethostname()
                    ]
                );

                // Optionally: trigger incident response
                $this->logger->critical('Autoload tampering detected', [
                    'action' => 'incident_triggered'
                ]);
            }
        }
    }

    private function fetchSecurityAdvisories(array $packageNames): array {
        $ch = curl_init(self::VULNERABILITY_DB);
        curl_setopt_array($ch, [
            CURLOPT_RETURNTRANSFER => true,
            CURLOPT_POST => true,
            CURLOPT_POSTFIELDS => json_encode(['packages' => $packageNames]),
            CURLOPT_HTTPHEADER => ['Content-Type: application/json'],
            CURLOPT_TIMEOUT => 30
        ]);

        $response = curl_exec($ch);
        curl_close($ch);

        return json_decode($response, true)['advisories'] ?? [];
    }

    private function isVersionAffected(string $version, array $advisory): bool {
        $affectedVersions = $advisory['affected_versions'] ?? '';
        return \Composer\Semver\Semver::satisfies($version, $affectedVersions);
    }

    private function mapSeverity(string $severity): string {
        return match(strtolower($severity)) {
            'critical', 'high' => 'CRITICAL',
            'medium' => 'HIGH',
            default => 'MEDIUM'
        };
    }

    private function getStoredHash(string $identifier): ?string {
        $hashFile = $this->projectRoot . '/.security-hashes.json';
        if (!file_exists($hashFile)) {
            return null;
        }
        $hashes = json_decode(file_get_contents($hashFile), true);
        return $hashes[$identifier] ?? null;
    }

    private function detectAbandonedPackages(): array {
        // Implementation for detecting abandoned packages
        return ['severity' => 'OK', 'abandoned' => []];
    }

    private function checkLicenseCompliance(): array {
        // Implementation for license checking
        return ['severity' => 'OK', 'issues' => []];
    }
}
```

```php
<?php
// CI/CD Pipeline integration - .github/workflows/security-scan.yml equivalent in PHP
// scripts/ci-security-check.php

declare(strict_types=1);

require __DIR__ . '/../vendor/autoload.php';

use App\Security\DependencySecurityManager;
use App\Logging\SecurityLogger;
use App\Monitoring\AlertingService;

$logger = new SecurityLogger();
$alerting = new AlertingService();
$manager = new DependencySecurityManager($logger, $alerting, dirname(__DIR__));

// Run comprehensive audit
try {
    $results = $manager->auditBeforeDeployment();

    // Generate SBOM (Software Bill of Materials)
    $sbom = generateSBOM(dirname(__DIR__) . '/composer.lock');
    file_put_contents(dirname(__DIR__) . '/sbom.json', json_encode($sbom, JSON_PRETTY_PRINT));

    echo "Security audit passed\n";
    echo json_encode($results, JSON_PRETTY_PRINT);
    exit(0);

} catch (RuntimeException $e) {
    echo "SECURITY AUDIT FAILED: " . $e->getMessage() . "\n";
    exit(1);
}

function generateSBOM(string $lockFile): array {
    $lockData = json_decode(file_get_contents($lockFile), true);
    $sbom = [
        'bomFormat' => 'CycloneDX',
        'specVersion' => '1.4',
        'version' => 1,
        'metadata' => [
            'timestamp' => date('c'),
            'tools' => [['name' => 'php-sbom-generator', 'version' => '1.0.0']]
        ],
        'components' => []
    ];

    foreach ($lockData['packages'] ?? [] as $package) {
        $sbom['components'][] = [
            'type' => 'library',
            'name' => $package['name'],
            'version' => $package['version'],
            'purl' => 'pkg:composer/' . $package['name'] . '@' . $package['version'],
            'hashes' => [
                ['alg' => 'SHA-256', 'content' => $package['dist']['shasum'] ?? '']
            ]
        ];
    }

    return $sbom;
}
